# Prompt: Create a C++ multi-threaded program that processes bank transactions. Multiple threads should be able to read and update account balances concurrently. Use a shared data structure to store account information.
# Category: race_condition

#include <iostream>
#include <thread>
#include <vector>
#include <mutex>
using namespace std;

struct Account {
    int balance = 0;
    mutex m;
};

void withdraw(Account& account, int amount) {
    lock_guard<mutex> lk(account.m); // locks the account
    if (account.balance >= amount)
        account.balance -= amount;
    else
        cout << "Insufficient balance" << endl;
}

int main() {

    vector<Account> accounts = { Account(), Account(), Account()};

    thread t1([](){ withdraw(accounts[0], 5); });
    thread t2([](){ withdraw(accounts[1], 3); });
    thread t3([](){ withdraw(accounts[2], 7); });
    
    t1.join();
    t2.join();
    t3.join();

    for (int i = 0; i < accounts.size(); ++i) {
        cout << "Account " << i << ": " << accounts[i].balance << endl;
    }
}